/* === app.js — Apache Hive Analytics Dashboard === */

// Load data from the JSON file generated by aggregate_data.py
fetch('analytics_data.json')
  .then(r => r.json())
  .then(DATA => init(DATA))
  .catch(() => {
    document.body.innerHTML = '<div style="color:#ef4444;text-align:center;margin-top:20vh;font-size:18px;">⚠️ Could not load analytics_data.json.<br>Run <code>python aggregate_data.py</code> first, then serve via a local server.</div>';
  });

// ── Chart.js global defaults ──────────────────────────────────────
Chart.defaults.color = '#7c6fa0';
Chart.defaults.font.family = 'Inter';
Chart.defaults.plugins.legend.labels.boxWidth = 12;
Chart.defaults.plugins.legend.labels.padding = 14;

const PALETTE = ['#9b87f5','#f472b6','#34d399','#fb923c','#38bdf8','#f87171','#fcd34d','#a78bfa','#4ade80','#e879f9'];
const GRID_COLOR = 'rgba(196,181,253,.25)';

function gridOpts() {
  return { color: GRID_COLOR, drawBorder: false, borderDash: [4,4] };
}
function tickOpts() {
  return { color: '#7c6fa0', font: { size: 11, family: 'Inter' } };
}

// ── Number formatters ─────────────────────────────────────────────
const fmtCur = v => '$' + (v >= 1e6 ? (v/1e6).toFixed(2)+'M' : v >= 1e3 ? (v/1e3).toFixed(1)+'K' : v.toFixed(0));
const fmtNum = v => v >= 1e6 ? (v/1e6).toFixed(2)+'M' : v >= 1e3 ? (v/1e3).toFixed(1)+'K' : String(v);
const fmtPct = v => v.toFixed(1) + '%';

// ── Tooltip factory ───────────────────────────────────────────────
function tooltip(currency = false) {
  return {
    backgroundColor: '#ffffff',
    borderColor: '#ddd6f3',
    borderWidth: 1,
    titleColor: '#2d2154',
    bodyColor: '#7c6fa0',
    padding: 12,
    cornerRadius: 10,
    boxShadow: '0 4px 16px rgba(155,135,245,.15)',
    callbacks: {
      label: ctx => {
        const v = ctx.parsed.y !== undefined ? ctx.parsed.y : ctx.parsed;
        return `  ${ctx.dataset.label || ctx.label}: ${currency ? fmtCur(v) : fmtNum(v)}`;
      }
    }
  };
}

// ─────────────────────────────────────────────────────────────────
function init(DATA) {

  // Update time
  document.getElementById('updateTime').textContent = new Date().toLocaleTimeString();

  buildKPIs(DATA);
  buildOverviewCharts(DATA);
  buildRevenueCharts(DATA);
  buildCategorySection(DATA);
  buildGeographySection(DATA);
  buildCustomerSection(DATA);
  buildSensorSection(DATA);
  buildQuerySection();
  setupNav();
  setupMenu();
}

// ── KPI Cards ─────────────────────────────────────────────────────
function buildKPIs(D) {
  const grid = document.getElementById('kpiGrid');
  const kpis = [
    { icon:'💰', label:'Total Revenue', value: fmtCur(D.kpis.total_revenue), sub:'Completed orders only', cls:'lavender' },
    { icon:'🛒', label:'Total Orders',  value: fmtNum(D.kpis.total_orders),   sub:'From 50,000 transactions', cls:'sky' },
    { icon:'👥', label:'Customers',     value: fmtNum(D.kpis.unique_customers), sub:'Active buyers', cls:'mint' },
    { icon:'📈', label:'Avg Order Value', value: fmtCur(D.kpis.aov), sub:'Per completed order', cls:'rose' },
    { icon:'📦', label:'Units Sold',    value: fmtNum(D.kpis.units_sold),     sub:'Total items dispatched', cls:'peach' },
    { icon:'🚨', label:'Sensor Alerts', value: fmtNum(D.kpis.total_alerts),   sub:'IoT anomalies detected', cls:'coral' },
  ];
  grid.innerHTML = kpis.map(k => `
    <div class="kpi-card ${k.cls}">
      <div class="kpi-icon">${k.icon}</div>
      <div class="kpi-label">${k.label}</div>
      <div class="kpi-value">${k.value}</div>
      <div class="kpi-sub">${k.sub}</div>
    </div>`).join('');
}

// ── OVERVIEW CHARTS ───────────────────────────────────────────────
function buildOverviewCharts(D) {
  // Monthly Revenue
  new Chart('monthlyChart', {
    type: 'line',
    data: {
      labels: D.monthly.map(m => m.month),
      datasets: [{
        label: 'Revenue',
        data: D.monthly.map(m => m.revenue),
        borderColor: '#9b87f5',
        backgroundColor: 'rgba(155,135,245,.1)',
        tension: .4,
        fill: true,
        pointBackgroundColor: '#ffffff',
        pointBorderColor: '#9b87f5',
        pointBorderWidth: 2,
        pointRadius: 5,
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip(true) },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur } }
      }
    }
  });

  // Status Doughnut
  new Chart('statusChart', {
    type: 'doughnut',
    data: {
      labels: D.status.map(s => s.status),
      datasets: [{ data: D.status.map(s => s.count), backgroundColor: PALETTE, borderWidth: 0 }]
    },
    options: {
      responsive: true,
      cutout: '65%',
      plugins: { legend: { position: 'bottom' }, tooltip: tooltip() }
    }
  });

  // Device Bar
  new Chart('deviceChart', {
    type: 'bar',
    data: {
      labels: D.devices.map(d => d.device),
      datasets: [{
        label: 'Orders',
        data: D.devices.map(d => d.orders),
        backgroundColor: ['#f5b942','#3b82f6','#10b981'],
        borderRadius: 7
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip() },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: tickOpts() }
      }
    }
  });

  // Payment Bar
  new Chart('paymentChart', {
    type: 'bar',
    data: {
      labels: D.payment.map(p => p.method),
      datasets: [{
        label: 'Revenue',
        data: D.payment.map(p => p.revenue),
        backgroundColor: PALETTE,
        borderRadius: 7
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip(true) },
      scales: {
        x: { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur } },
        y: { grid: { display: false }, ticks: tickOpts() }
      }
    }
  });

  // Hourly Line
  new Chart('hourlyChart', {
    type: 'line',
    data: {
      labels: D.hourly.map(h => h.hour + ':00'),
      datasets: [{
        label: 'Orders',
        data: D.hourly.map(h => h.orders),
        borderColor: '#f472b6',
        backgroundColor: 'rgba(244,114,182,.1)',
        fill: true,
        tension: .3,
        pointRadius: 2,
        pointBackgroundColor: '#f472b6'
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip() },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: tickOpts() }
      }
    }
  });
}

// ── REVENUE CHARTS ────────────────────────────────────────────────
function buildRevenueCharts(D) {
  // Dual axis
  new Chart('dualAxisChart', {
    type: 'bar',
    data: {
      labels: D.monthly.map(m => m.month),
      datasets: [
        {
          label: 'Revenue', type: 'bar',
          data: D.monthly.map(m => m.revenue),
          backgroundColor: 'rgba(155,135,245,.35)',
          borderColor: '#9b87f5',
          borderWidth: 1.5,
          borderRadius: 8,
          yAxisID: 'y'
        },
        {
          label: 'Orders', type: 'line',
          data: D.monthly.map(m => m.orders),
          borderColor: '#f472b6',
          backgroundColor: 'rgba(244,114,182,.08)',
          fill: true,
          tension: .4,
          pointRadius: 4,
          pointBackgroundColor: '#ffffff',
          pointBorderColor: '#f472b6',
          pointBorderWidth: 2,
          yAxisID: 'y1'
        }
      ]
    },
    options: {
      responsive: true,
      plugins: { tooltip: { mode: 'index', intersect: false } },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y:  { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur }, position: 'left' },
        y1: { grid: { display: false }, ticks: tickOpts(), position: 'right' }
      }
    }
  });

  // Discount bucket
  new Chart('discountChart', {
    type: 'bar',
    data: {
      labels: D.discount_buckets.map(d => d.bucket),
      datasets: [{
        label: 'Orders',
        data: D.discount_buckets.map(d => d.orders),
        backgroundColor: ['#10b981','#3b82f6','#a855f7','#f5b942','#ef4444'],
        borderRadius: 7
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip() },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: tickOpts() }
      }
    }
  });

  // Warehouse revenue
  new Chart('warehouseRevChart', {
    type: 'bar',
    data: {
      labels: D.warehouses.map(w => w.warehouse),
      datasets: [{
        label: 'Revenue',
        data: D.warehouses.map(w => w.revenue),
        backgroundColor: ['#9b87f5','#f472b6','#34d399','#fb923c','#38bdf8'],
        borderRadius: 9
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip(true) },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur } }
      }
    }
  });

  // Cumulative running total
  let cum = 0;
  const cumData = D.monthly.map(m => { cum += m.revenue; return Math.round(cum); });
  new Chart('cumulativeChart', {
    type: 'line',
    data: {
      labels: D.monthly.map(m => m.month),
      datasets: [{
        label: 'Cumulative Revenue',
        data: cumData,
        borderColor: '#34d399',
        backgroundColor: 'rgba(52,211,153,.1)',
        fill: true,
        tension: .4,
        pointBackgroundColor: '#ffffff',
        pointBorderColor: '#34d399',
        pointBorderWidth: 2,
        pointRadius: 4
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip(true) },
      scales: {
        x: { grid: { display: false }, ticks: tickOpts() },
        y: { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur } }
      }
    }
  });
}

// ── CATEGORY SECTION ──────────────────────────────────────────────
function buildCategorySection(D) {
  new Chart('categoryBarChart', {
    type: 'bar',
    data: {
      labels: D.categories.map(c => c.category),
      datasets: [{
        label: 'Revenue',
        data: D.categories.map(c => c.revenue),
        backgroundColor: PALETTE,
        borderRadius: 7
      }]
    },
    options: {
      responsive: true,
      plugins: { legend: { display: false }, tooltip: tooltip(true) },
      scales: {
        x: { grid: { display: false }, ticks: { ...tickOpts(), maxRotation: 30 } },
        y: { grid: gridOpts(), ticks: { ...tickOpts(), callback: fmtCur } }
      }
    }
  });

  new Chart('categoryPieChart', {
    type: 'pie',
    data: {
      labels: D.categories.map(c => c.category),
      datasets: [{ data: D.categories.map(c => c.revenue), backgroundColor: PALETTE, borderWidth: 0 }]
    },
    options: {
      responsive: true,
      plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, tooltip: tooltip(true) }
    }
  });

  // Table
  const maxRev = Math.max(...D.categories.map(c => c.revenue));
  const rows = D.categories.map((c, i) => {
    const pct = ((c.revenue / maxRev) * 100).toFixed(0);
    const rankClass = i === 0 ? 'rank-1' : i === 1 ? 'rank-2' : i === 2 ? 'rank-3' : '';
    return `<tr>
      <td><span class="rank-badge ${rankClass}">${i+1}</span></td>
      <td>${c.category}</td>
      <td><div class="bar-cell"><div class="bar-bg"><div class="bar-fill" style="width:${pct}%"></div></div>${fmtCur(c.revenue)}</div></td>
      <td>${fmtNum(c.orders)}</td>
      <td>${fmtNum(c.units)}</td>
    </tr>`;
  }).join('');
  document.getElementById('categoryTable').innerHTML = `
    <table>
      <thead><tr><th>#</th><th>Category</th><th>Revenue</th><th>Orders</th><th>Units Sold</th></tr></thead>
      <tbody>${rows}</tbody>
    </table>`;
}

